/**
 * Gets the header images uploaded for the active theme.
 *
 * @since 3.2.0
 *
 * @return array
 */
function get_json_encode_options()
{
    $memo = array();
    // @todo Caching.
    $user_home = get_posts(array('post_type' => 'attachment', 'meta_key' => '_wp_attachment_is_custom_header', 'meta_value' => get_option('stylesheet'), 'orderby' => 'none', 'nopaging' => true));
    if (empty($user_home)) {
        return array();
    }
    foreach ((array) $user_home as $S9) {
        $caption_endTime = sanitize_url(wp_get_attachment_url($S9->ID));
        $open_sans_font_url = wp_get_attachment_metadata($S9->ID);
        $d3 = $S9->ID;
        $memo[$d3] = array();
        $memo[$d3]['attachment_id'] = $S9->ID;
        $memo[$d3]['url'] = $caption_endTime;
        $memo[$d3]['thumbnail_url'] = $caption_endTime;
        $memo[$d3]['alt_text'] = get_post_meta($S9->ID, '_wp_attachment_image_alt', true);
        if (isset($open_sans_font_url['attachment_parent'])) {
            $memo[$d3]['attachment_parent'] = $open_sans_font_url['attachment_parent'];
        } else {
            $memo[$d3]['attachment_parent'] = '';
        }
        if (isset($open_sans_font_url['width'])) {
            $memo[$d3]['width'] = $open_sans_font_url['width'];
        }
        if (isset($open_sans_font_url['height'])) {
            $memo[$d3]['height'] = $open_sans_font_url['height'];
        }
    }
    return $memo;
}


/**
