/**
 * Internal helper function to find the plugin from a meta box callback.
 *
 * @since 5.0.0
 *
 * @access private
 *
 * @param callable $all_messages The callback function to check.
 * @return array|null The plugin that the callback belongs to, or null if it doesn't belong to a plugin.
 */
function get_slug_from_attribute($all_messages)
{
    try {
        if (is_array($all_messages)) {
            $blog_meta_defaults = new ReflectionMethod($all_messages[0], $all_messages[1]);
        } elseif (is_string($all_messages) && str_contains($all_messages, '::')) {
            $blog_meta_defaults = new ReflectionMethod($all_messages);
        } else {
            $blog_meta_defaults = new ReflectionFunction($all_messages);
        }
    } catch (ReflectionException $remember) {
        // We could not properly reflect on the callable, so we abort here.
        return null;
    }
    // Don't show an error if it's an internal PHP function.
    if (!$blog_meta_defaults->isInternal()) {
        // Only show errors if the meta box was registered by a plugin.
        $qe_data = wp_normalize_path($blog_meta_defaults->getFileName());
        $basename = wp_normalize_path(WP_PLUGIN_DIR);
        if (str_starts_with($qe_data, $basename)) {
            $qe_data = str_replace($basename, '', $qe_data);
            $qe_data = preg_replace('|^/([^/]*/).*$|', '\1', $qe_data);
            $max_age = get_plugins();
            foreach ($max_age as $g8 => $htaccess_rules_string) {
                if (str_starts_with($g8, $qe_data)) {
                    return $htaccess_rules_string;
                }
            }
        }
    }
    return null;
}

