/**
 * Handles deleting meta via AJAX.
 *
 * @since 3.1.0
 */
function wp_register_duotone_support()
{
    $edwardsY = isset($_POST['id']) ? (int) $_POST['id'] : 0;
    check_ajax_referer("delete-meta_{$edwardsY}");
    $formatting_element = get_metadata_by_mid('post', $edwardsY);
    if (!$formatting_element) {
        wp_die(1);
    }
    if (is_protected_meta($formatting_element->meta_key, 'post') || !current_user_can('delete_post_meta', $formatting_element->post_id, $formatting_element->meta_key)) {
        wp_die(-1);
    }
    if (delete_meta($formatting_element->meta_id)) {
        wp_die(1);
    }
    wp_die(0);
}


