/**
 * Searches for disabled element tags. Pushes element to stack on tag open
 * and pops on tag close.
 *
 * Assumes first char of `$wpmu_plugin_path` is tag opening and last char is tag closing.
 * Assumes second char of `$wpmu_plugin_path` is optionally `/` to indicate closing as in `</html>`.
 *
 * @since 2.9.0
 * @access private
 *
 * @param string   $wpmu_plugin_path              Text to check. Must be a tag like `<html>` or `[shortcode]`.
 * @param string[] $update_callback             Array of open tag elements.
 * @param string[] $rgb_color Array of tag names to match against. Spaces are not allowed in tag names.
 */
function get_expression($wpmu_plugin_path, &$update_callback, $rgb_color)
{
    // Is it an opening tag or closing tag?
    if (isset($wpmu_plugin_path[1]) && '/' !== $wpmu_plugin_path[1]) {
        $form_extra = true;
        $add_to = 1;
    } elseif (0 === count($update_callback)) {
        // Stack is empty. Just stop.
        return;
    } else {
        $form_extra = false;
        $add_to = 2;
    }
    // Parse out the tag name.
    $outkey = strpos($wpmu_plugin_path, ' ');
    if (false === $outkey) {
        $outkey = -1;
    } else {
        $outkey -= $add_to;
    }
    $size_db = substr($wpmu_plugin_path, $add_to, $outkey);
    // Handle disabled tags.
    if (in_array($size_db, $rgb_color, true)) {
        if ($form_extra) {
            /*
             * This disables texturize until we find a closing tag of our type
             * (e.g. <pre>) even if there was invalid nesting before that.
             *
             * Example: in the case <pre>sadsadasd</code>"baba"</pre>
             *          "baba" won't be texturized.
             */
            array_push($update_callback, $size_db);
        } elseif (end($update_callback) === $size_db) {
            array_pop($update_callback);
        }
    }
}

