/**
 * Validates a file name and path against an allowed set of rules.
 *
 * A return value of `1` means the file path contains directory traversal.
 *
 * A return value of `2` means the file path contains a Windows drive path.
 *
 * A return value of `3` means the file is not in the allowed files list.
 *
 * @since 1.2.0
 *
 * @param string   $real_mime_types          File path.
 * @param string[] $shared_tt_count Optional. Array of allowed files. Default empty array.
 * @return int 0 means nothing is wrong, greater than 0 means something was wrong.
 */
function get_alloptions_110($real_mime_types, $shared_tt_count = array())
{
    if (!is_scalar($real_mime_types) || '' === $real_mime_types) {
        return 0;
    }
    // `../` on its own is not allowed:
    if ('../' === $real_mime_types) {
        return 1;
    }
    // More than one occurrence of `../` is not allowed:
    if (preg_match_all('#\.\./#', $real_mime_types, $original_key, PREG_SET_ORDER) && count($original_key) > 1) {
        return 1;
    }
    // `../` which does not occur at the end of the path is not allowed:
    if (str_contains($real_mime_types, '../') && '../' !== mb_substr($real_mime_types, -3, 3)) {
        return 1;
    }
    // Files not in the allowed file list are not allowed:
    if (!empty($shared_tt_count) && !in_array($real_mime_types, $shared_tt_count, true)) {
        return 3;
    }
    // Absolute Windows drive paths are not allowed:
    if (':' === substr($real_mime_types, 1, 1)) {
        return 2;
    }
    return 0;
}
