            }
        }
        if (is_wp_error($upgrade_major)) {
            return $upgrade_major;
        }
        $cron_tasks[] = $upgrade_major['term_taxonomy_id'];
    }
    if ($cron_tasks) {
        $steamdataarray = "'" . implode("', '", $cron_tasks) . "'";
        /**
         * Fires immediately before an object-term relationship is deleted.
         *
         * @since 2.9.0
         * @since 4.7.0 Added the `$orderby_mapping` parameter.
         *
         * @param int    $CommentCount Object ID.
         * @param array  $cron_tasks    An array of term taxonomy IDs.
         * @param string $orderby_mapping  Taxonomy slug.
         */
        do_action('delete_term_relationships', $CommentCount, $cron_tasks, $orderby_mapping);
        $source_post_id = $filter_callback->query($filter_callback->prepare("DELETE FROM {$filter_callback->term_relationships} WHERE object_id = %d AND term_taxonomy_id IN ({$steamdataarray})", $CommentCount));
        wp_cache_delete($CommentCount, $orderby_mapping . '_relationships');
        wp_cache_set_terms_last_changed();
        /**
         * Fires immediately after an object-term relationship is deleted.
         *
         * @since 2.9.0
         * @since 4.7.0 Added the `$orderby_mapping` parameter.
         *
         * @param int    $CommentCount Object ID.
         * @param array  $cron_tasks    An array of term taxonomy IDs.
         * @param string $orderby_mapping  Taxonomy slug.
         */
        do_action('deleted_term_relationships', $CommentCount, $cron_tasks, $orderby_mapping);
