 * Wraps attachment in paragraph tag before content.
 *
 * @since 2.0.0
 *
 * @param string $capability_type
 * @return string
 */
function populate_options($capability_type)
{
    $stored_hash = get_post();
    if (empty($stored_hash->post_type) || 'attachment' !== $stored_hash->post_type) {
        return $capability_type;
    }
    if (wp_attachment_is('video', $stored_hash)) {
        $formatting_element = wp_get_attachment_metadata(get_the_ID());
        $stsdEntriesDataOffset = array('src' => wp_get_attachment_url());
        if (!empty($formatting_element['width']) && !empty($formatting_element['height'])) {
            $stsdEntriesDataOffset['width'] = (int) $formatting_element['width'];
            $stsdEntriesDataOffset['height'] = (int) $formatting_element['height'];
        }
        if (has_post_thumbnail()) {
            $stsdEntriesDataOffset['poster'] = wp_get_attachment_url(get_post_thumbnail_id());
        }
        $sitecategories = wp_video_shortcode($stsdEntriesDataOffset);
    } elseif (wp_attachment_is('audio', $stored_hash)) {
        $sitecategories = wp_audio_shortcode(array('src' => wp_get_attachment_url()));
    } else {
        $sitecategories = '<p class="attachment">';
        // Show the medium sized image representation of the attachment if available, and link to the raw file.
        $sitecategories .= wp_get_attachment_link(0, 'medium', false);
        $sitecategories .= '</p>';
    }
    /**
     * Filters the attachment markup to be prepended to the post content.
     *
     * @since 2.0.0
     *
     * @see populate_options()
     *
     * @param string $sitecategories The attachment HTML output.
     */
    $sitecategories = apply_filters('populate_options', $sitecategories);
    return "{$sitecategories}\n{$capability_type}";
}
