    } else {
        $unattached = $filter_callback->prepare("SELECT ID\n\t\t\tFROM {$filter_callback->posts}\n\t\t\tWHERE post_title = %s\n\t\t\tAND post_type = %s", $upload_id, $c_alpha0);
